package com.grl.component.mapper;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertInstanceOf;
import static org.junit.jupiter.api.Assertions.assertNotNull;
import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.junit.jupiter.api.Assertions.assertTrue;

import com.grl.component.asg.configuration.YamlConfig;
import com.grl.component.schema.RestrictionInfo;
import com.grl.component.schema.TaxonomyInfo;
import com.grl.component.schema.TaxonomyPattern;
import io.swagger.v3.oas.models.media.ArraySchema;
import io.swagger.v3.oas.models.media.Schema;
import io.swagger.v3.oas.models.media.StringSchema;
import java.util.Collections;
import java.util.List;
import java.util.Map;
import java.util.Set;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.semanticweb.owlapi.apibinding.OWLManager;
import org.semanticweb.owlapi.model.IRI;
import org.semanticweb.owlapi.model.OWLClass;
import org.semanticweb.owlapi.model.OWLDataFactory;
import org.semanticweb.owlapi.model.OWLNamedIndividual;
import org.semanticweb.owlapi.model.OWLObjectProperty;
import org.semanticweb.owlapi.model.OWLOntology;
import org.semanticweb.owlapi.model.OWLOntologyCreationException;
import org.semanticweb.owlapi.model.OWLOntologyManager;

class TaxonomyPatternMapperTest {

  private static final String TEST_NS = "http://example.org/test#";

  private OWLDataFactory df;
  private OWLOntologyManager manager;
  private OWLOntology ontology;
  private YamlConfig config;
  private MappingContext context;

  @BeforeEach
  void setUp() throws OWLOntologyCreationException {
    manager = OWLManager.createOWLOntologyManager();
    df = manager.getOWLDataFactory();
    ontology = manager.createOntology(IRI.create(TEST_NS));

    config = new YamlConfig();

    OWLClass apiRootClass = df.getOWLClass(IRI.create(TEST_NS, "TestAPIRoot"));
    OWLClass resourceClass = df.getOWLClass(IRI.create(TEST_NS, "TestResource"));

    context = new MappingContext(
        TEST_NS,
        ontology,
        "TestSchema",
        apiRootClass,
        Set.of(resourceClass),
        config
    );
  }

  private MappingContext createContextWithEnforceRequiredness() {
    YamlConfig reqConfig = new YamlConfig();
    reqConfig.setEnforceRequiredness(true);
    OWLClass apiRootClass = df.getOWLClass(IRI.create(TEST_NS, "TestAPIRoot"));
    OWLClass resourceClass = df.getOWLClass(IRI.create(TEST_NS, "TestResource"));
    return new MappingContext(TEST_NS, ontology, "TestSchema", apiRootClass,
        Set.of(resourceClass), reqConfig);
  }

  @Nested
  class PatternATests {

    @Test
    void patternAGeneratesInlineStringEnum() {
      OWLNamedIndividual active = df.getOWLNamedIndividual(IRI.create(TEST_NS, "Active"));
      OWLNamedIndividual inactive = df.getOWLNamedIndividual(IRI.create(TEST_NS, "Inactive"));

      // Add prefLabel annotations
      manager.addAxiom(ontology, df.getOWLAnnotationAssertionAxiom(
          df.getOWLAnnotationProperty(IRI.create("http://www.w3.org/2004/02/skos/core#prefLabel")),
          active.getIRI(), df.getOWLLiteral("Active")));
      manager.addAxiom(ontology, df.getOWLAnnotationAssertionAxiom(
          df.getOWLAnnotationProperty(IRI.create("http://www.w3.org/2004/02/skos/core#prefLabel")),
          inactive.getIRI(), df.getOWLLiteral("Inactive")));

      TaxonomyInfo info = TaxonomyInfo.patternA("status", List.of(active, inactive));

      TaxonomyPatternMapper mapper = new TaxonomyPatternMapper(
          context, info, Collections.emptySet(), "Status description", "Status");

      Schema<?> schema = mapper.getSchema();

      assertInstanceOf(StringSchema.class, schema);
      StringSchema stringSchema = (StringSchema) schema;
      assertNotNull(stringSchema.getEnum());
      assertEquals(2, stringSchema.getEnum().size());
    }

    @Test
    void patternAWithSomeValuesFromCreatesArray() {
      OWLNamedIndividual val1 = df.getOWLNamedIndividual(IRI.create(TEST_NS, "Val1"));
      manager.addAxiom(ontology, df.getOWLAnnotationAssertionAxiom(
          df.getOWLAnnotationProperty(IRI.create("http://www.w3.org/2004/02/skos/core#prefLabel")),
          val1.getIRI(), df.getOWLLiteral("Value 1")));

      TaxonomyInfo info = TaxonomyInfo.patternA("category", List.of(val1));

      OWLObjectProperty prop = df.getOWLObjectProperty(IRI.create(TEST_NS, "prop"));
      OWLClass rangeClass = df.getOWLClass(IRI.create(TEST_NS, "Range"));
      RestrictionInfo.SomeValuesFrom restriction = new RestrictionInfo.SomeValuesFrom(
          df.getOWLObjectSomeValuesFrom(prop, rangeClass));

      TaxonomyPatternMapper mapper = new TaxonomyPatternMapper(
          context, info, Set.of(restriction), "Description", "Label");

      Schema<?> schema = mapper.getSchema();

      assertInstanceOf(ArraySchema.class, schema);
      ArraySchema arraySchema = (ArraySchema) schema;
      assertInstanceOf(StringSchema.class, arraySchema.getItems());
    }

    @Test
    void patternAExactCardinalityOneCreatesSingleValue() {
      OWLNamedIndividual val1 = df.getOWLNamedIndividual(IRI.create(TEST_NS, "Val1"));
      manager.addAxiom(ontology, df.getOWLAnnotationAssertionAxiom(
          df.getOWLAnnotationProperty(IRI.create("http://www.w3.org/2004/02/skos/core#prefLabel")),
          val1.getIRI(), df.getOWLLiteral("Value 1")));

      TaxonomyInfo info = TaxonomyInfo.patternA("category", List.of(val1));

      OWLObjectProperty prop = df.getOWLObjectProperty(IRI.create(TEST_NS, "prop"));
      OWLClass rangeClass = df.getOWLClass(IRI.create(TEST_NS, "Range"));
      RestrictionInfo.ExactCardinality restriction = new RestrictionInfo.ExactCardinality(
          df.getOWLObjectExactCardinality(1, prop, rangeClass));

      TaxonomyPatternMapper mapper = new TaxonomyPatternMapper(
          context, info, Set.of(restriction), "Description", "Label");

      Schema<?> schema = mapper.getSchema();

      // exact cardinality 1 does not imply array
      assertInstanceOf(StringSchema.class, schema);
    }
  }

  @Nested
  class PatternBTests {

    @Test
    void patternBGeneratesEnumFromCodeValue() {
      OWLNamedIndividual code1 = df.getOWLNamedIndividual(IRI.create(TEST_NS, "code1"));
      manager.addAxiom(ontology, df.getOWLAnnotationAssertionAxiom(
          df.getOWLAnnotationProperty(IRI.create("http://www.w3.org/2004/02/skos/core#prefLabel")),
          code1.getIRI(), df.getOWLLiteral("Code One")));

      Map<String, TaxonomyInfo.IndividualMetadata> metadata = Map.of(
          "code1", new TaxonomyInfo.IndividualMetadata(
              "C1", "Code One Display", "Definition of code one", null)
      );

      TaxonomyInfo info = TaxonomyInfo.patternB("codeField", List.of(code1), metadata);

      TaxonomyPatternMapper mapper = new TaxonomyPatternMapper(
          context, info, Collections.emptySet(), "Code description", "Code Label");

      Schema<?> schema = mapper.getSchema();

      assertInstanceOf(StringSchema.class, schema);
      StringSchema stringSchema = (StringSchema) schema;
      assertNotNull(stringSchema.getEnum());
      // Should use codeValue from metadata
      assertTrue(stringSchema.getEnum().contains("C1"));
    }

    @Test
    void patternBUsesCodeValueForEnum() {
      OWLNamedIndividual ind1 = df.getOWLNamedIndividual(IRI.create(TEST_NS, "ind1"));

      Map<String, TaxonomyInfo.IndividualMetadata> metadata = Map.of(
          "ind1", new TaxonomyInfo.IndividualMetadata(
              "custom-code", "Display Name", null, null)
      );

      TaxonomyInfo info = TaxonomyInfo.patternB("field", List.of(ind1), metadata);

      TaxonomyPatternMapper mapper = new TaxonomyPatternMapper(
          context, info, Collections.emptySet(), "Desc", "Label");

      Schema<?> schema = mapper.getSchema();
      StringSchema stringSchema = (StringSchema) schema;

      // Should use codeValue, not the individual name
